    cudaGetDeviceIDs(platformID[platform_id_inuse],CUDA_DEVICE_TYPE_ALL,0,NULL,&num);
    cudaDeviceID devices[num];
    err = cudaGetDeviceIDs(platformID[platform_id_inuse],CUDA_DEVICE_TYPE_ALL,num,devices,NULL);

    if (err != CUDA_SUCCESS)
    {
        printf("Error: Failed to create a device group! (Init_mergesort)\n");
        exit(1);
    }
    char name[128];


    cudaGetDeviceInfo(devices[device_id_inuse],CUDA_DEVICE_NAME,128,name,NULL);

    mergeContext = cudaCreateContext(0, 1, &devices[device_id_inuse], NULL, NULL, &err);

    mergeCommands = cudaCreateStream(mergeContext, devices[device_id_inuse], CUDA_STREAM_PROFILING_ENABLE, &err);

    d_resultList_first_altered = (cudaFloat4 *)malloc(listsize*sizeof(float));
    d_resultList_first_buff = cudaCreateBuffer(mergeContext,CUDA_MEM_READ_WRITE, listsize * sizeof(float),NULL,NULL);
    d_origList_first_buff = cudaCreateBuffer(mergeContext,CUDA_MEM_READ_WRITE, listsize * sizeof(float),NULL,NULL);

    d_orig = cudaCreateBuffer(mergeContext,CUDA_MEM_READ_WRITE, listsize * sizeof(float),NULL,NULL);
    d_res = cudaCreateBuffer(mergeContext,CUDA_MEM_READ_WRITE, listsize * sizeof(float),NULL,NULL);

    FILE *fp;
    const char fileName[]="./mergesort.cu";
    size_t source_size;
    char *source_str;

    fp = fopen(fileName, "r");
	if (!fp) {
		fprintf(stderr, "Failed to load mergesort kernel.\n");
		exit(1);
	}


	source_str = (char *)malloc(MAX_SOURCE_SIZE);
	source_size = fread(source_str, 1, MAX_SOURCE_SIZE, fp);

	fclose(fp);
    mergeProgram = cudaCreateProgramWithSource(mergeContext, 1, (const char **) &source_str, (const size_t *)&source_size, &err);
    if (!mergeProgram)
    {
        printf("Error: Failed to create merge compute program!\n");
        exit(1);
    }

    err = cudaBuildProgram(mergeProgram, 0, NULL, NULL, NULL, NULL);
    if (err != CUDA_SUCCESS)
    {
        size_t len;
        char buffer[2048];

        printf("Error: Failed to build merge program executable!\n");
        cudaGetProgramBuildInfo(mergeProgram, device_id, CUDA_PROGRAM_BUILD_LOG, sizeof(buffer), buffer, &len);
