}

void finish_mergesort() {
    cudaReleaseMemObject(constStartAddr);
    cudaReleaseMemObject(nullElems);
    cudaReleaseMemObject(finalStartAddr);
    cudaReleaseMemObject(d_orig);
    cudaReleaseMemObject(d_res);
    cudaReleaseMemObject(d_origList_first_buff);
    cudaReleaseMemObject(d_resultList_first_buff);
    cudaReleaseProgram(mergeProgram);
    cudaReleaseKernel(mergeFirstKernel);
    cudaReleaseStream(mergeCommands);
    cudaReleaseContext(mergeContext);
}
cudaFloat4* runMergeSort(int listsize, int divisions,
                        cudaFloat4 *d_origList, cudaFloat4 *d_resultList,
                        int *sizes, int *nullElements,
                        unsigned int *origOffsets){

