    {
        printf("Error: Failed to write to d_resultList_first_buff source array!\n");
        exit(1);
    }
    err = cudaEnqueueWriteBuffer(mergeCommands, d_origList_first_buff, CUDA_TRUE, 0, listsize*sizeof(float), d_origList, 0, NULL, &write_event[1]);
