    err  = cudaSetKernelArg(mergeFirstKernel, 2, sizeof(cudaInt), &listsize);
    if (err != CUDA_SUCCESS)
    {
        printf("Error: Failed to set merge first kernel arguments! %d\n", err);
        exit(1);
    }
#ifdef MERGE_WG_SIZE_0
    const int THREADS = MERGE_WG_SIZE_0;
#else
    const int THREADS = 256;
#endif
    size_t local[] = {THREADS,1,1};
	int blocks = ((listsize/4)%THREADS == 0) ? (listsize/4)/THREADS : (listsize/4)/THREADS + 1;
	size_t global[] = {blocks*THREADS,1,1};
    size_t grid[] = {blocks,1,1,1};

    err = cudaEnqueueNDRangeKernel(mergeCommands, mergeFirstKernel, 3, NULL, global, local, 0, NULL, &mergeFirstEvent);
    if (err)
    {
        printf("Error: Failed to execute mergeFirst kernel!\n");
        exit(1);
    }
    cudaWaitForEvents(1 , &mergeFirstEvent);
    cudaFinish(mergeCommands);

    err = cudaEnqueueReadBuffer( mergeCommands, d_resultList_first_buff, CUDA_TRUE, 0, listsize*sizeof(float), d_resultList, 0, NULL, &read_event[0]);
