    kernel_time += probe_event_time(mergeFirstEvent, mergeCommands);
#endif
    cudaReleaseEvent(write_event[0]);
    cudaReleaseEvent(write_event[1]);
    cudaReleaseEvent(read_event[0]);







    cudaUlong time_start, time_end;
    double total_time;
    cudaGetEventProfilingInfo(mergeFirstEvent, CUDA_PROFILING_COMMAND_START, sizeof(time_start), &time_start, NULL);
    cudaGetEventProfilingInfo(mergeFirstEvent, CUDA_PROFILING_COMMAND_END, sizeof(time_end), &time_end, NULL);
    total_time = time_end - time_start;
